import{_ as e,a as i,b as s,c as t,d as o,e as n}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as r,c as l,a2 as c}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"Geolocalización IP y gestión de usuarios","description":"","frontmatter":{},"headers":[],"relativePath":"es/Other/ip-geolocation-and-user-management.md","filePath":"es/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),p={name:"es/Other/ip-geolocation-and-user-management.md"};function u(m,a,g,h,b,f){return r(),l("div",null,[...a[0]||(a[0]=[c('<h1 id="geolocalizacion-ip-y-gestion-de-usuarios" tabindex="-1">Geolocalización IP y gestión de usuarios <a class="header-anchor" href="#geolocalizacion-ip-y-gestion-de-usuarios" aria-label="Permalink to &quot;Geolocalización IP y gestión de usuarios&quot;">​</a></h1><p>La geolocalización IP convierte las IP de registros de subida, dispositivos de inicio de sesión y otros logs en ubicaciones aproximadas.</p><p>Con esta función configurada, el panel muestra mejor el origen de subidas y accesos. La gestión de usuarios también permite bloquear o restaurar la capacidad de subir archivos para IP sospechosas.</p><h2 id="donde-se-configura" tabindex="-1">Dónde se configura <a class="header-anchor" href="#donde-se-configura" aria-label="Permalink to &quot;Dónde se configura&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Configuración del sistema -&gt; Otros ajustes -&gt; Geolocalización IP</span></span></code></pre></div><p><img src="'+e+`" alt="Geolocalización IP" loading="lazy"></p><h2 id="ajustes-disponibles" tabindex="-1">Ajustes disponibles <a class="header-anchor" href="#ajustes-disponibles" aria-label="Permalink to &quot;Ajustes disponibles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ajuste</th><th>Descripción</th></tr></thead><tbody><tr><td>Idioma de geolocalización</td><td>Define el idioma de las ubicaciones mostradas</td></tr><tr><td>MaxMind Account ID</td><td>ID de cuenta para MaxMind GeoLite Web Service</td></tr><tr><td>MaxMind License Key</td><td>Clave de licencia de MaxMind</td></tr><tr><td>Tencent Map Key</td><td>Útil para direcciones de China continental</td></tr><tr><td>ipapi Key</td><td>Clave de APILayer ipapi con soporte multilingüe</td></tr></tbody></table><p>Rellena solo los servicios que necesites. Si no configuras claves, ImgBed intentará usar fuentes gratuitas integradas, aunque pueden ser menos estables o precisas.</p><h2 id="recomendacion-para-espanol" tabindex="-1">Recomendación para español <a class="header-anchor" href="#recomendacion-para-espanol" aria-label="Permalink to &quot;Recomendación para español&quot;">​</a></h2><p>Si quieres mostrar ubicaciones en español o en varios idiomas, configura MaxMind y, si necesitas mejores resultados multilingües, añade ipapi.</p><h2 id="configurar-maxmind" tabindex="-1">Configurar MaxMind <a class="header-anchor" href="#configurar-maxmind" aria-label="Permalink to &quot;Configurar MaxMind&quot;">​</a></h2><p>MaxMind necesita:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Busca el Account ID en el panel de MaxMind y crea una License Key desde la página correspondiente. Después pega ambos valores en ImgBed.</p><p><img src="`+i+'" alt="Configuración MaxMind" loading="lazy"></p><h2 id="configurar-ipapi" tabindex="-1">Configurar ipapi <a class="header-anchor" href="#configurar-ipapi" aria-label="Permalink to &quot;Configurar ipapi&quot;">​</a></h2><p>Copia la API Key desde la consola de ipapi.</p><p><img src="'+s+'" alt="Configuración ipapi" loading="lazy"></p><p>Pégala en el campo <code>ipapi Key</code> dentro de ImgBed y guarda.</p><h2 id="gestion-de-usuarios" tabindex="-1">Gestión de usuarios <a class="header-anchor" href="#gestion-de-usuarios" aria-label="Permalink to &quot;Gestión de usuarios&quot;">​</a></h2><p>La gestión de usuarios se abre desde la parte superior del panel de administración.</p><p><img src="'+t+'" alt="Gestión de usuarios" loading="lazy"></p><p>Muestra la actividad agrupada por IP.</p><table tabindex="0"><thead><tr><th>Campo</th><th>Descripción</th></tr></thead><tbody><tr><td>IP</td><td>IP de origen</td></tr><tr><td>Ubicación</td><td>Ubicación aproximada resuelta desde la IP</td></tr><tr><td>Tamaño total subido</td><td>Suma de archivos subidos por esa IP</td></tr><tr><td>Número de subidas</td><td>Cantidad de subidas</td></tr><tr><td>Subida permitida</td><td>Si se desactiva, esa IP ya no podrá subir</td></tr></tbody></table><p>Abre la flecha de la izquierda para revisar los archivos subidos por esa IP. Verás nombre, vista previa, tamaño, resultado de revisión, estado y hora de subida.</p><p><img src="'+o+'" alt="Filtros avanzados" loading="lazy"></p><h2 id="consejos-de-operacion" tabindex="-1">Consejos de operación <a class="header-anchor" href="#consejos-de-operacion" aria-label="Permalink to &quot;Consejos de operación&quot;">​</a></h2><ul><li>Antes de bloquear una IP, revisa los archivos que subió.</li><li>Usa búsqueda y ordenación para detectar IP recientes, muy activas o con mucho consumo.</li><li>La ubicación IP es una estimación. Úsala como señal de apoyo, no como prueba absoluta.</li></ul><p><img src="'+n+'" alt="Vista móvil" loading="lazy"></p>',30)])])}const _=d(p,[["render",u]]);export{x as __pageData,_ as default};
